{
  "extractionPromptAddendum": "In addition to standard elements, pay special attention to: 
- **Events**: For significant incidents like crimes, add an `is_crime: true` attribute to the `Event` or `Proposition` node representing it.
- **Evidence**: Identify specific observations, objects, or statements presented as 'evidence'. Represent them as `Proposition` nodes with `type: 'evidence'`. If evidence supports or contradicts another proposition, add `supports: [proposition_id]` or `contradicts: [proposition_id]` attributes. Note the `source` of the evidence if specified. If the evidence pertains to a specific `location` or `time_frame`, include those attributes. If it links to a specific entity, add `entity: [entity_id]`.
- **Suspects**: Identify characters explicitly named or strongly implied as 'suspects'. Add a `status: 'suspect'` attribute to their `Entity` node.
- **Alibis**: Identify statements or facts presented as an 'alibi' for a suspect. Represent these as `Proposition` nodes with `type: 'alibi'`, linking them to the `suspect` entity (ID) and the `time_frame` they cover. Also, include the `location` attribute if the alibi specifies a place.
- **Motives**: Identify stated or implied 'motives' for actions. Represent these as `Proposition` nodes with `type: 'motive'`, linking them to the `entity` (ID) and the `action` (event ID) it explains. If a motive is tied to a specific `crime` event, link it via `explains_action: [event_id]`.",
  "verificationCode": "function verify(graph, context) {
    var results = [];

    // Helper to find nodes by type and optional attribute filters
    function findNodes(type, attributeFilters = {}) {
        return graph.nodes.filter(node => {
            if (node.type !== type) return false;
            for (const key in attributeFilters) {
                if (!node.attributes || node.attributes[key] !== attributeFilters[key]) return false;
            }
            return true;
        });
    }

    // Helper to parse time frames (simplified: YYYY-MM-DDTHH:MM or YYYY-MM-DDTHH:MM-HH:MM)
    // Returns { start: Date, end: Date } or null if invalid
    function parseTimeFrame(tfString) {
        if (!tfString) return null;
        const parts = tfString.split('-');
        try {
            const start = new Date(parts[0]);
            const end = parts.length > 1 ? new Date(parts[1]) : start; // If no end, it's a point in time
            if (isNaN(start.getTime()) || isNaN(end.getTime())) return null;
            return { start, end };
        } catch (e) {
            return null;
        }
    }

    // Helper to check for temporal overlap
    function doTimeFramesOverlap(tf1String, tf2String) {
        const tf1 = parseTimeFrame(tf1String);
        const tf2 = parseTimeFrame(tf2String);

        if (!tf1 || !tf2) return false;

        // Check for overlap: [start1, end1] and [start2, end2] overlap if start1 <= end2 AND start2 <= end1
        return tf1.start.getTime() <= tf2.end.getTime() && tf2.start.getTime() <= tf1.end.getTime();
    }

    // --- Custom Check 1: Alibi Contradiction ---
    // An alibi for a suspect is contradicted by other established facts or evidence.
    const alibis = findNodes('Proposition', { type: 'alibi' });
    const allPropositions = graph.nodes.filter(node => node.type === 'Proposition' || node.type === 'Event');

    alibis.forEach(alibi => {
        const suspectId = alibi.attributes.suspect;
        const alibiTimeFrame = alibi.attributes.time_frame;
        const alibiLocation = alibi.attributes.location;

        if (!suspectId || !alibiTimeFrame) {
            results.push({
                check: 'AlibiConsistency',
                level: 'warning',
                message: `Alibi '${alibi.id}' is missing a linked suspect or time frame.`, 
                nodes: [alibi.id]
            });
            return;
        }

        allPropositions.forEach(otherProp => {
            if (alibi.id === otherProp.id) return; // Don't compare an alibi to itself

            const otherPropTimeFrame = otherProp.attributes ? otherProp.attributes.time_frame : undefined;
            const otherPropLocation = otherProp.attributes ? otherProp.attributes.location : undefined;

            // Check for explicit contradiction link
            if (otherProp.attributes && otherProp.attributes.contradicts && otherProp.attributes.contradicts.includes(alibi.id)) {
                if (doTimeFramesOverlap(alibiTimeFrame, otherPropTimeFrame)) {
                    results.push({
                        check: 'AlibiContradiction',
                        level: 'error',
                        message: `Alibi '${alibi.id}' for suspect '${suspectId}' is explicitly contradicted by proposition '${otherProp.id}' and their time frames overlap.`, 
                        nodes: [alibi.id, otherProp.id, suspectId]
                    });
                } else {
                    results.push({
                        check: 'AlibiContradiction',
                        level: 'warning',
                        message: `Alibi '${alibi.id}' for suspect '${suspectId}' is explicitly contradicted by proposition '${otherProp.id}', but their time frames do not overlap. Consider if the contradiction is still valid.`, 
                        nodes: [alibi.id, otherProp.id, suspectId]
                    });
                }
            }

            // Heuristic check for implicit contradiction for the same suspect at overlapping times
            // This relies on 'location' attributes being present and distinct.
            if (otherProp.attributes && (otherProp.attributes.type === 'evidence' || otherProp.attributes.status === 'established_fact')) {
                if (otherProp.attributes.entity === suspectId && doTimeFramesOverlap(alibiTimeFrame, otherPropTimeFrame)) {
                    if (alibiLocation && otherPropLocation && alibiLocation !== otherPropLocation) {
                        results.push({
                            check: 'AlibiContradiction',
                            level: 'error',
                            message: `Alibi '${alibi.id}' for suspect '${suspectId}' (at ${alibiLocation}) is implicitly contradicted by '${otherProp.id}' (at ${otherPropLocation}) for the same suspect at overlapping times.`, 
                            nodes: [alibi.id, otherProp.id, suspectId]
                        });
                    }
                }
            }
        });
    });

    // --- Custom Check 2: Suspect without Primary Evidence or Motive ---
    // A suspect is identified, but there's no direct evidence or motive strongly linking them to a central crime/incident.
    const suspects = findNodes('Entity', { status: 'suspect' });
    const crimeEvents = graph.nodes.filter(node => (node.type === 'Event' || node.type === 'Proposition') && node.attributes && node.attributes.is_crime === true);

    suspects.forEach(suspect => {
        const suspectId = suspect.id;
        let hasDirectEvidence = false;
        let hasMotive = false;

        // Check for direct evidence linking to the suspect and a crime
        const evidences = findNodes('Proposition', { type: 'evidence' });
        evidences.forEach(evidence => {
            if (evidence.attributes.entity === suspectId &&
                evidence.attributes.supports && crimeEvents.some(ce => evidence.attributes.supports.includes(ce.id))) {
                hasDirectEvidence = true;
            }
        });

        // Check for motive linking to the suspect and a crime
        const motives = findNodes('Proposition', { type: 'motive' });
        motives.forEach(motive => {
            if (motive.attributes.entity === suspectId &&
                motive.attributes.explains_action && crimeEvents.some(ce => motive.attributes.explains_action === ce.id)) {
                hasMotive = true;
            }
        });

        if (!hasDirectEvidence && !hasMotive) {
            results.push({
                check: 'SuspectPlausibility',
                level: 'warning',
                message: `Suspect '${suspect.attributes.name || suspect.id}' has no direct evidence or motive linking them to a crime.`, 
                nodes: [suspect.id]
            });
        }
    });

    return results;
}"
}
